INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd40d42ee-7a81-4b9f-9d91-1ac7f9f02c7c',
  '00000000-0000-0000-0000-000000000001',
  $escape$QUIC's Congestion Control: CUBIC, BBR, and the role of ACKs$escape$,
  $escape$QUIC employs a congestion control mechanism based on TCP's CUBIC and BBR algorithms. When a QUIC receiver acknowledges packets, it updates the sender's congestion window. CUBIC uses an exponential backoff algorithm to minimize packet losses during congestion episodes. In contrast, BBR (Bottleneck Bandwidth and Round-trip time) estimates the available bandwidth and adjusts the congestion window accordingly. Unlike TCP, QUIC's congestion control does not rely on packet losses to adjust the window size; instead, it uses ACK packets to monitor the available bandwidth and adjust the congestion window proactively.$escape$,
  NULL,
  NULL,
